    /// <summary>
    /// Provides safe redaction utilities for sensitive data in logs.
    /// </summary>
    public static class LogSanitizer
    {
        private static readonly HashSet<string> SensitiveHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Authorization",
            "Cookie",
            "Set-Cookie",
            "X-API-Key",
            "X-Auth-Token",
            "Proxy-Authorization",
            "WWW-Authenticate"
        };

        private static readonly HashSet<string> SensitiveBodyFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "password",
            "token",
            "secret",
            "creditCard",
            "credit_card",
            "cardNumber",
            "card_number",
            "cvv",
            "ssn",
            "social_security",
            "socialSecurity",
            "accessToken",
            "access_token",
            "refreshToken",
            "refresh_token",
            "apiKey",
            "api_key",
            "privateKey",
            "private_key"
        };

        public static Dictionary<string, string> SanitizeHeaders(IHeaderDictionary headers)
        {
            var sanitized = new Dictionary<string, string>();
            foreach (var header in headers)
            {
                if (SensitiveHeaders.Contains(header.Key))
                {
                    sanitized[header.Key] = "[REDACTED]";
                }
                else
                {
                    sanitized[header.Key] = header.Value.ToString();
                }
            }
            return sanitized;
        }

        public static string SanitizeBody(string body)
        {
            if (string.IsNullOrWhiteSpace(body))
                return body;

            try
            {
                var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(body);
                if (obj == null) return "[unparseable content]";

                var sanitized = new Dictionary<string, object>();
                foreach (var kvp in obj)
                {
                    if (SensitiveBodyFields.Contains(kvp.Key))
                    {
                        sanitized[kvp.Key] = "[REDACTED]";
                    }
                    else
                    {
                        sanitized[kvp.Key] = kvp.Value;
                    }
                }
                return JsonConvert.SerializeObject(sanitized);
            }
            catch
            {
                // If we can't parse, don't log raw body as it might contain sensitive data
                return "[non-JSON body, content redacted for safety]";
            }
        }

        public static string SanitizeUserId(string userId)
        {
            if (string.IsNullOrEmpty(userId) || userId.Length <= 4)
                return "[REDACTED]";

            // Show only last 4 characters
            return "***" + userId.Substring(userId.Length - 4);
        }

        public static string SanitizeEmail(string email)
        {
            if (string.IsNullOrEmpty(email))
                return "[REDACTED]";

            var atIndex = email.IndexOf('@');
            if (atIndex <= 1)
                return "[REDACTED]";

            return email[0] + "***" + email.Substring(atIndex);
        }

        public static string RedactSqlParameters(Dictionary<string, object> parameters)
        {
            if (parameters == null) return "{}";

            var redacted = new Dictionary<string, string>();
            var sensitiveParamNames = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "password", "token", "secret", "ssn", "creditcard", "apikey"
            };

            foreach (var param in parameters)
            {
                bool isSensitive = sensitiveParamNames.Any(s => param.Key.IndexOf(s, StringComparison.OrdinalIgnoreCase) >= 0);
                redacted[param.Key] = isSensitive ? "[REDACTED]" : param.Value?.ToString() ?? "null";
            }

            return JsonConvert.SerializeObject(redacted);
        }

        public static string SanitizeException(Exception ex)
        {
            // Log exception type, message, and stack trace but scrub potential sensitive data from message
            var message = ex.Message;

            // Remove potential connection strings from exception messages
            message = System.Text.RegularExpressions.Regex.Replace(
                message,
                @"(Server|Data Source|Initial Catalog|User Id|Password|Integrated Security|Connection Timeout)\s*=\s*[^;]+",
                "$1=[REDACTED]",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);

            return $"ExceptionType: {ex.GetType().FullName}, Message: {message}, StackTrace: {ex.StackTrace}";
        }
    }

    /// <summary>
    /// Represents a correlation context for request tracing without exposing sensitive data.
    /// </summary>
    public class RequestCorrelation
    {
        public string CorrelationId { get; set; }
        public string RequestPath { get; set; }
        public string HttpMethod { get; set; }
        public string SanitizedUserId { get; set; }
        public DateTime Timestamp { get; set; }
    }

    public static class SecureCustomerOrderFunction
    {
        [FunctionName("SecureProcessOrder")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", "post", "put", "delete", Route = "orders/{orderId?}")] HttpRequest req,
            string orderId,
            ILogger log)
        {
            // Generate a correlation ID for tracing without logging sensitive data
            var correlationId = Guid.NewGuid().ToString("N").Substring(0, 12);

            var correlation = new RequestCorrelation
            {
                CorrelationId = correlationId,
                RequestPath = req.Path.Value,
                HttpMethod = req.Method,
                Timestamp = DateTime.UtcNow
            };

            log.LogInformation(
                "Request started. CorrelationId: {CorrelationId}, Method: {Method}, Path: {Path}",
                correlation.CorrelationId,
                correlation.HttpMethod,
                correlation.RequestPath);

            // Log SAFE headers only (sensitive ones are redacted)
            var sanitizedHeaders = LogSanitizer.SanitizeHeaders(req.Headers);
            log.LogDebug(
                "Request headers (sanitized). CorrelationId: {CorrelationId}, Headers: {Headers}",
                correlationId,
                JsonConvert.SerializeObject(sanitizedHeaders));

            try
            {
                // Read and sanitize body
                string requestBody;
                using (var reader = new StreamReader(req.Body))
                {
                    requestBody = await reader.ReadToEndAsync();
                }

                var sanitizedBody = LogSanitizer.SanitizeBody(requestBody);
                log.LogDebug(
                    "Request body (sanitized). CorrelationId: {CorrelationId}, Body: {Body}",
                    correlationId,
                    sanitizedBody);

                // Extract user identity safely
                string userId = null;
                string userEmail = null;

                if (req.HttpContext.User?.Identity?.IsAuthenticated == true)
                {
                    userId = req.HttpContext.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
                    userEmail = req.HttpContext.User.FindFirst(ClaimTypes.Email)?.Value;
                }

                // Log sanitized user context
                log.LogInformation(
                    "User context. CorrelationId: {CorrelationId}, UserId: {UserId}, Email: {Email}, IsAuthenticated: {IsAuthenticated}",
                    correlationId,
                    LogSanitizer.SanitizeUserId(userId),
                    LogSanitizer.SanitizeEmail(userEmail),
                    req.HttpContext.User?.Identity?.IsAuthenticated ?? false);

                // Process the request
                var result = await ProcessOrderSecurely(orderId, requestBody, correlationId, log);

                log.LogInformation(
                    "Request completed successfully. CorrelationId: {CorrelationId}, StatusCode: 200",
                    correlationId);

                return new OkObjectResult(result);
            }
            catch (SqlException sqlEx)
            {
                // Log SQL errors without connection strings or sensitive parameters
                log.LogError(
                    "Database error. CorrelationId: {CorrelationId}, ErrorNumber: {ErrorNumber}, Sanitized: {SanitizedException}",
                    correlationId,
                    sqlEx.Number,
                    LogSanitizer.SanitizeException(sqlEx));

                return new StatusCodeResult(StatusCodes.Status500InternalServerError);
            }
            catch (UnauthorizedAccessException authEx)
            {
                log.LogWarning(
                    "Unauthorized access attempt. CorrelationId: {CorrelationId}, Message: {Message}",
                    correlationId,
                    authEx.Message);

                return new UnauthorizedResult();
            }
            catch (Exception ex)
            {
                // Log sanitized exception details
                log.LogError(
                    "Unhandled exception. CorrelationId: {CorrelationId}, SanitizedException: {SanitizedException}",
                    correlationId,
                    LogSanitizer.SanitizeException(ex));

                // If there's an inner exception, log it too (sanitized)
                if (ex.InnerException != null)
                {
                    log.LogError(
                        "Inner exception. CorrelationId: {CorrelationId}, SanitizedException: {SanitizedException}",
                        correlationId,
                        LogSanitizer.SanitizeException(ex.InnerException));
                }

                return new StatusCodeResult(StatusCodes.Status500InternalServerError);
            }
        }

        private static async Task<object> ProcessOrderSecurely(string orderId, string requestBody, string correlationId, ILogger log)
        {
            // Use environment variable or Azure Key Vault for connection strings - NEVER log them
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            if (string.IsNullOrEmpty(connectionString))
            {
                log.LogError("Database connection string not configured. CorrelationId: {CorrelationId}", correlationId);
                throw new InvalidOperationException("Database configuration missing.");
            }

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                // Log the query template but NOT the actual parameter values for sensitive fields
                var query = "SELECT OrderId, Status, CreatedDate, TotalAmount FROM Orders WHERE OrderId = @OrderId";

                var parameters = new Dictionary<string, object>
                {
                    { "@OrderId", orderId }
                };

                log.LogDebug(
                    "Executing query. CorrelationId: {CorrelationId}, Query: {Query}, Parameters: {Parameters}",
                    correlationId,
                    query,
                    LogSanitizer.RedactSqlParameters(parameters));

                using (var command = new SqlCommand(query, connection))
                {
                    command.Parameters.AddWithValue("@OrderId", orderId ?? (object)DBNull.Value);

                    var startTime = DateTime.UtcNow;

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        var duration = (DateTime.UtcNow - startTime).TotalMilliseconds;

                        log.LogDebug(
                            "Query completed. CorrelationId: {CorrelationId}, DurationMs: {Duration}, HasResults: {HasResults}",
                            correlationId,
                            duration,
                            reader.HasRows);

                        if (await reader.ReadAsync())
                        {
                            return new
                            {
                                OrderId = reader["OrderId"]?.ToString(),
                                Status = reader["Status"]?.ToString(),
                                CreatedDate = reader["CreatedDate"],
                                TotalAmount = reader["TotalAmount"]
                            };
                        }

                        log.LogWarning(
                            "Order not found. CorrelationId: {CorrelationId}, OrderId: {OrderId}",
                            correlationId,
                            orderId);

                        return null;
                    }
                }
            }
        }
    }

    /// <summary>
    /// Health check function that demonstrates safe diagnostic logging.
