    public static class SecureHealthCheckFunction
    {
        [FunctionName("SecureHealthCheck")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", Route = "health")] HttpRequest req,
            ILogger log)
        {
            var correlationId = Guid.NewGuid().ToString("N").Substring(0, 12);

            log.LogInformation("Health check initiated. CorrelationId: {CorrelationId}", correlationId);

            var healthStatus = new Dictionary<string, string>();

            // Check database connectivity without logging connection details
            try
            {
                var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
                using (var connection = new SqlConnection(connectionString))
                {
                    await connection.OpenAsync();
                    healthStatus["Database"] = "Healthy";
                    log.LogInformation("Database health check passed. CorrelationId: {CorrelationId}", correlationId);
                }
            }
            catch (Exception ex)
            {
                healthStatus["Database"] = "Unhealthy";
                // Log sanitized exception - no connection string details
                log.LogError(
                    "Database health check failed. CorrelationId: {CorrelationId}, Error: {Error}",
                    correlationId,
                    LogSanitizer.SanitizeException(ex));
            }

            healthStatus["Timestamp"] = DateTime.UtcNow.ToString("O");
            healthStatus["CorrelationId"] = correlationId;

            return new OkObjectResult(healthStatus);
        }
